import "./App.css";
/**
 *
 * App <=> parent component
 * Feature <=> child component
 *
 * App có thể chứa nhiều Feature, nhưng Feature không thể chứa App
 */

/** Component YoutubeItem */
const YoutubeItem = (props) => {
  const { title, author } = props;

  return (
    <div className="youtube-item">
      <div className="youtube-image">
        <img
          src="https://images.unsplash.com/photo-1768487422639-7ba3900d0f02"
          alt="ảnh-1"
        />
      </div>
      <div className="youtube-footer">
        <img
          src="https://images.unsplash.com/photo-1768487422639-7ba3900d0f02"
          alt=""
          className="youtube-avt"
        />
        <div className="youtube-info">
          <h3 className="youtube-title">Youtube Title</h3>
          <h4 className="youtube-author">Youtube Author</h4>
        </div>
      </div>
    </div>
  );
};
/** End YoutubeItem */

/**
 * App <=> parent component
 * Feature <=> child component
 * YoutubeItem <=> child component
 * */

const App = () => {
  return (
    <>
      <YoutubeItem />
    </>
  );
};

export default App;
